<!-- /web-pages/Profiles.html -->

{% include 'snippet' snippet_name:'FetchXML - SetupQuery' %} {% if is_admin != true and is_RoleAssign != true and has_admin_backdoor != true %}
<!-- PROFILE01 -->
<script>
       (function() {
  let redir = "~/";

  if (G_Roles.isAdmin || G_Roles.isAssign || (window.DEBUG_AdminVars && window.DEBUG_AdminVars.has_admin_backdoor)) {
  	// console.log("Profiles: admin or assign, so no redirect");
